-- ============================================================================
-- supabase/seed.sql — GENERATED by `pnpm gen:seed` from lib/catalog/*.
-- DO NOT EDIT BY HAND. Prices live in lib/catalog/data.ts (single source of
-- truth, spec B1). Idempotent: safe to run repeatedly via `pnpm db:seed`.
-- All pricing is PLACEHOLDER — the admin reviews it before launch.
-- ============================================================================

on conflict (slug) do update set name = excluded.name, short_name = excluded.short_name, divisions_per_tier = excluded.divisions_per_tier, is_active = excluded.is_active, sort_order = excluded.sort_order;

on conflict (type) do update set slug = excluded.slug, name = excluded.name, short = excluded.short, blurb = excluded.blurb, is_active = excluded.is_active, sort_order = excluded.sort_order;

on conflict (game_slug, sort_index) do update set tier = excluded.tier, division = excluded.division, label = excluded.label, climb_price_cents = excluded.climb_price_cents, climb_eta_hours = excluded.climb_eta_hours, is_purchasable = excluded.is_purchasable;

on conflict (game_slug, band) do update set label = excluded.label, price_per_game_cents = excluded.price_per_game_cents, min_games = excluded.min_games, max_games = excluded.max_games, eta_per_game_hours = excluded.eta_per_game_hours;

on conflict (game_slug, group_key) do update set label = excluded.label, price_per_win_cents = excluded.price_per_win_cents, tiers = excluded.tiers, eta_per_win_hours = excluded.eta_per_win_hours;

on conflict (key) do update set label = excluded.label, description = excluded.description, kind = excluded.kind, amount = excluded.amount, eta_multiplier = excluded.eta_multiplier, is_default_on = excluded.is_default_on, is_active = excluded.is_active, sort_order = excluded.sort_order, game_slug = excluded.game_slug, service_type = excluded.service_type, hidden_in_duo = excluded.hidden_in_duo;

on conflict (game_slug, code) do update set label = excluded.label, multiplier = excluded.multiplier, is_default = excluded.is_default, sort_order = excluded.sort_order;

on conflict (code) do update set kind = excluded.kind, amount = excluded.amount, min_order_cents = excluded.min_order_cents, max_uses = excluded.max_uses, expires_at = excluded.expires_at, is_active = excluded.is_active;

on conflict (name) do update set min_lifetime_spend_cents = excluded.min_lifetime_spend_cents, discount_bp = excluded.discount_bp, cashback_bp = excluded.cashback_bp, sort_order = excluded.sort_order;

on conflict (key) do update set value = excluded.value;
